try{var teu=await this.helpers.httpRequest({method:'GET',url:'https://tech.eu/feed/',timeout:10000});var reTE=new RegExp('<title>([^<]+)</title>','g');var mTE;var cntTE=0;while((mTE=reTE.exec(teu))!==null&&cntTE<4){var tTE=mTE[1].trim();if(tTE!=='Tech.eu'&&tTE.length>10){allItems.push({baslik:tTE,kaynak:'Tech.eu',puan:0,yorum:0,ozet:'',url:'',kategori:'tech'});cntTE++;}}}catch(e){}
try{var cbn=await this.helpers.httpRequest({method:'GET',url:'https://news.crunchbase.com/feed/',timeout:10000});var reCB=new RegExp('<title>([^<]+)</title>','g');var mCB;var cntCB=0;while((mCB=reCB.exec(cbn))!==null&&cntCB<4){var tCB=mCB[1].trim();if(tCB!=='Crunchbase News'&&tCB.length>10){allItems.push({baslik:tCB,kaynak:'Crunchbase',puan:0,yorum:0,ozet:'',url:'',kategori:'tech'});cntCB++;}}}catch(e){}
