// === DEDUP ===
var filtered = allItems.filter(function(item) {
  return eskiBasliklar.indexOf(item.baslik.toLowerCase().trim()) === -1;
});
if (filtered.length === 0) {
  throw new Error('Tum icerikler daha once paylasilmis, yeni icerik yok.');
}

// === AGIRLIKLI RASTGELE KATEGORI SECIMI ===
var rand = Math.random() * 100;
var secilenKategori = '';
if (rand < 30) secilenKategori = 'reddit';
else if (rand < 50) secilenKategori = 'turkiye';
else if (rand < 70) secilenKategori = 'dunya';
else if (rand < 85) secilenKategori = 'tech';
else secilenKategori = 'github';

var kategoriItems = filtered.filter(function(item) { return item.kategori === secilenKategori; });
if (kategoriItems.length === 0) kategoriItems = filtered;

kategoriItems.sort(function(a,b){return(b.puan+b.yorum*2)-(a.puan+a.yorum*2);});

var best;
if (secilenKategori === 'reddit' || secilenKategori === 'github') {
  best = kategoriItems[0];
} else {
  var rastgeleIdx = Math.floor(Math.random() * Math.min(kategoriItems.length, 5));
  best = kategoriItems[rastgeleIdx];
}

// === RASTGELE FORMAT SECIMI ===
var formatRand = Math.random() * 100;
var formatTipi = '';
if (formatRand < 40) formatTipi = 'flood';
else if (formatRand < 65) formatTipi = 'tek_post';
else if (formatRand < 85) formatTipi = 'arac_tanitim';
else formatTipi = 'soru_tartisma';

// GitHub kategorisinde arac_tanitim oncelikli
if (secilenKategori === 'github') formatTipi = (Math.random() < 0.7) ? 'arac_tanitim' : 'flood';

return[{json:{baslik:best.baslik,kaynak:best.kaynak,puan:best.puan,yorum:best.yorum,ozet:best.ozet,url:best.url,kategori:secilenKategori,formatTipi:formatTipi,toplamIcerik:allItems.length,yeniIcerik:filtered.length,tarih:new Date().toISOString()}}];

