try{
  var resp=await this.helpers.httpRequest({method:'POST',url:'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key='+GEMINI_KEY,headers:{'Content-Type':'application/json'},body:JSON.stringify({contents:[{parts:[{text:prompt}]}],generationConfig:{temperature:0.85,maxOutputTokens:4096,topP:0.9}}),timeout:90000});
  var data=typeof resp==='string'?JSON.parse(resp):resp;
  var raw=data.candidates[0].content.parts[0].text||'';
  raw=raw.replace(/```json
?/g,'').replace(/```
?/g,'').trim();
  var s=raw.indexOf('{');var e=raw.lastIndexOf('}');
  if(s===-1||e===-1)throw new Error('JSON yok');
  var parsed=JSON.parse(raw.substring(s,e+1));
  if(!parsed.hook||parsed.hook.length<50)throw new Error('hook bos');
  var hookText=parsed.hook;
  if(haberUrl&&hookText.indexOf('http')===-1)hookText=hookText.trim()+'

'+haberUrl;
  return[{json:{baslik:item.baslik,kaynak:item.kaynak,url:haberUrl,puan:item.puan,hookTweet:hookText,flood1:parsed.t1||'',flood2:parsed.t2||'',flood3:parsed.t3||'',ctaTweet:parsed.cta||'',formatTipi:formatTipi,kategori:item.kategori||'',durum:'HAZIR',tarih:item.tarih}}];
}catch(err){
